import{_ as a,c as m,o as e,f as t}from"./plugin-vue_export-helper.ecc8ebe5.js";const b='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-07T00:00:00.000Z"},"relativePath":"texts/shiva-sutra-vimarshini/3/6.md","lastUpdated":1626124605854}',r={},i=t('<div class="stanza"><a href="#s3.6" id="s3.6" class="num">3.6</a><div class="sans"><p>\u090F\u0935\u0902 \u0926\u0947\u0939\u0936\u0941\u0926\u094D\u0927\u093F\u092D\u0942\u0924\u0936\u0941\u0926\u094D\u0927\u093F\u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0939\u093E\u0930\u0927\u093E\u0930\u0923\u093E\u0927\u094D\u092F\u093E\u0928\u0938\u092E\u093E\u0927\u093F\u092D\u093F\u0930\u094D\u092F\u093E \u0924\u0924\u094D\u0924\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0930\u0942\u092A\u093E \u0938\u093F\u0926\u094D\u0927\u093F\u0930\u094D\u092D\u0935\u0924\u093F \u0938\u093E \u092E\u094B\u0939\u093E\u0935\u0930\u0923\u093E\u0928\u094D\u0928 \u0924\u0941 \u0924\u0924\u094D\u0924\u094D\u0935\u091C\u094D\u091E\u093E\u0928\u093E\u0926\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u092E\u094B\u0939\u093E\u0935\u0930\u0923\u093E\u0924\u094D\u0938\u093F\u0926\u094D\u0927\u093F\u0903\u0965\u096C\u0965</strong></p></blockquote><p>\u092E\u094B\u0939\u092F\u0924\u0940\u0924\u093F \u092E\u094B\u0939\u094B \u092E\u093E\u092F\u093E \u0924\u0924\u094D\u0915\u0943\u0924\u093E\u0926\u093E\u0935\u0930\u0923\u093E\u0924\u094D\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0927\u093E\u0930\u0923\u093E\u0926\u093F\u0915\u094D\u0930\u092E\u0938\u092E\u093E\u0938\u093E\u0926\u093F\u0924\u093E \u0924\u0924\u094D\u0924\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u092D\u094B\u0917\u0930\u0942\u092A\u093E \u0938\u093F\u0926\u094D\u0927\u093F\u0930\u094D\u092D\u0935\u0924\u093F\u0964 \u0928 \u0924\u0941 \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u092A\u094D\u0930\u0915\u093E\u0936\u0903\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0932\u094D\u0932\u0915\u094D\u0937\u094D\u092E\u0940\u0915\u094C\u0932\u093E\u0930\u094D\u0923\u0935\u0947</p><blockquote><p>\u0938\u094D\u0935\u092F\u092E\u094D\u092D\u0942\u0930\u094D\u092D\u0917\u0935\u093E\u0928\u094D\u0926\u0947\u0935\u094B \u091C\u0928\u094D\u092E\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u0935\u0930\u094D\u091C\u093F\u0924\u0903\u0964<br> \u0928\u093F\u0930\u094D\u0935\u093F\u0915\u0932\u094D\u092A\u0902 \u092A\u0930\u0902 \u0927\u093E\u092E \u0905\u0928\u093E\u0926\u093F\u0928\u093F\u0927\u0928\u0902 \u0936\u093F\u0935\u092E\u094D\u0965<br> \u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937\u0902 \u0938\u0930\u094D\u0935\u091C\u0928\u094D\u0924\u0942\u0928\u093E\u0902 \u0928 \u091A \u092A\u0936\u094D\u092F\u0924\u093F \u092E\u094B\u0939\u093F\u0924\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0935\u093F\u0917\u0932\u093F\u0924\u092E\u094B\u0939\u0938\u094D\u092F \u0924\u0941</p><blockquote><p>\u092E\u0927\u094D\u092F\u092E\u0902 \u092A\u094D\u0930\u093E\u0923\u092E\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u092A\u0925\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0906\u0932\u092E\u094D\u092C\u094D\u092F \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u093F\u0902 \u091A \u0924\u0924\u094D\u0938\u094D\u0925\u0902 \u091A\u0948\u0935\u093E\u0938\u0928\u0902 \u0932\u092D\u0947\u0924\u094D\u0965<br> \u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093F\u0938\u094D\u0925\u0942\u0932\u092D\u093E\u0935\u0902 \u0924\u0941 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u0925\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E\u0924\u0940\u0924\u0902 \u0924\u0941 \u092A\u0930\u092E\u0902 \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u0902 \u0932\u092D\u094D\u092F\u0924\u0947 \u092F\u0924\u0903\u0965<br> \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0903 \u0938 \u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u0924\u094B \u092F\u0938\u094D\u092E\u093E\u0928\u094D\u0928 \u091A\u094D\u092F\u0935\u0924\u0947 \u092A\u0941\u0928\u0903\u0964<br> \u0936\u092C\u094D\u0926\u093E\u0926\u093F\u0917\u0941\u0923\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u092F\u093E \u091A\u0947\u0924\u0938\u093E \u0939\u094D\u092F\u0928\u0941\u092D\u0942\u092F\u0924\u0947\u0965<br> \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0924\u093E\u0902 \u092A\u0930\u092E\u0902 \u0927\u093E\u092E \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0924\u0924\u094D\u0938\u094D\u0935\u091A\u0947\u0924\u0938\u093E\u0964<br> \u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0939\u093E\u0930 \u0907\u0924\u093F \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u094B \u092D\u0935\u092A\u093E\u0936\u0928\u093F\u0915\u0943\u0928\u094D\u0924\u0928\u0903\u0965<br> \u0927\u0940\u0917\u0941\u0923\u093E\u0928\u094D\u0938\u092E\u0924\u093F\u0915\u094D\u0930\u092E\u094D\u092F \u0928\u093F\u0930\u094D\u0927\u094D\u092F\u0947\u092F\u0902 \u092A\u0930\u092E\u0902 \u0935\u093F\u092D\u0941\u092E\u094D\u0964<br> \u0927\u094D\u092F\u093E\u0924\u094D\u0935\u093E \u0927\u094D\u092F\u0947\u092F\u0902 \u0938\u094D\u0935\u0938\u0902\u0935\u0947\u0926\u094D\u092F\u0902 \u0927\u094D\u092F\u093E\u0928\u0902 \u0924\u091A\u094D\u091A \u0935\u093F\u0926\u0941\u0930\u094D\u092C\u0941\u0927\u093E\u0903\u0965<br> \u0927\u093E\u0930\u0923\u093E \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0902 \u0927\u093E\u0930\u094D\u092F\u0924\u0947 \u092F\u0947\u0928 \u0938\u0930\u094D\u0935\u0926\u093E\u0964<br> \u0927\u093E\u0930\u0923\u093E \u0938\u093E \u0935\u093F\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u093E \u092D\u0935\u092A\u093E\u0936\u0928\u093F\u0935\u093E\u0930\u093F\u0923\u0940\u0965<br> \u0938\u094D\u0935\u092A\u0930\u0938\u094D\u0925\u0947\u0937\u0941 \u092D\u0942\u0924\u0947\u0937\u0941 \u091C\u0917\u0924\u094D\u092F\u0938\u094D\u092E\u093F\u0928\u094D\u0938\u092E\u093E\u0928\u0927\u0940\u0903\u0964<br> \u0936\u093F\u0935\u094B\u093D\u0939\u092E\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u094B\u093D\u0939\u0902 \u0938\u092E\u093E\u0927\u093F\u0903 \u0938 \u092A\u0930\u0903 \u0938\u094D\u092E\u0943\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0926\u094D\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0927\u093E\u0930\u0923\u093E\u0926\u093F\u092D\u093F\u0930\u092A\u093F \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u092E\u093E\u0935\u0947\u0936 \u090F\u0935 \u092D\u0935\u0924\u093F \u0928 \u0924\u0941 \u092E\u093F\u0924\u0938\u093F\u0926\u094D\u0927\u093F\u0903\u0965\u096C\u0965</p></div><hr><div class="trans"><p>Eva\u1E41 deha\u015Buddhibh\u016Bta\u015Buddhipr\u0101\u1E47\u0101y\u0101mapraty\u0101h\u0101radh\u0101ra\u1E47\u0101dhy\u0101nasam\u0101dhibhiry\u0101 tattattattvar\u016Bp\u0101 siddhirbhavati s\u0101 moh\u0101vara\u1E47\u0101nna tu tattvaj\xF1\u0101n\u0101dity\u0101ha\u2014</p><blockquote><p><strong>Moh\u0101vara\u1E47\u0101tsiddhi\u1E25||6||</strong></p></blockquote><p>Mohayat\u012Bti moho m\u0101y\u0101 tatk\u1E5Bt\u0101d\u0101vara\u1E47\u0101tproktadh\u0101ra\u1E47\u0101dikramasam\u0101s\u0101dit\u0101 tattattattvabhogar\u016Bp\u0101 siddhirbhavati| Na tu paratattvaprak\u0101\u015Ba\u1E25| Yadukta\u1E41 \u015Br\u012Bmallak\u1E63m\u012Bkaul\u0101r\u1E47ave</p><blockquote><p>Svayambh\u016Brbhagav\u0101ndevo janmasa\u1E41sk\u0101ravarjita\u1E25|<br> Nirvikalpa\u1E41 para\u1E41 dh\u0101ma an\u0101dinidhana\u1E41 \u015Bivam||<br> Pratyak\u1E63a\u1E41 sarvajant\u016Bn\u0101\u1E41 na ca pa\u015Byati mohita\u1E25|</p></blockquote><p>iti| Vigalitamohasya tu</p><blockquote><p>Madhyama\u1E41 pr\u0101\u1E47am\u0101\u015Britya pr\u0101\u1E47\u0101p\u0101napath\u0101ntaram|<br> \u0100lambya j\xF1\u0101na\u015Bakti\u1E41 ca tatstha\u1E41 caiv\u0101sana\u1E41 labhet||<br> Pr\u0101\u1E47\u0101disth\u016Blabh\u0101va\u1E41 tu tyaktv\u0101 s\u016Bk\u1E63mamath\u0101ntaram|<br> S\u016Bk\u1E63m\u0101t\u012Bta\u1E41 tu parama\u1E41 spandana\u1E41 labhyate yata\u1E25||<br> Pr\u0101\u1E47\u0101y\u0101ma\u1E25 sa nirdi\u1E63to yasm\u0101nna cyavate puna\u1E25|<br> \u015Aabd\u0101digu\u1E47av\u1E5Bttiry\u0101 cetas\u0101 hyanubh\u016Byate||<br> Tyaktv\u0101 t\u0101\u1E41 parama\u1E41 dh\u0101ma pravi\u015Bettatsvacetas\u0101|<br> Praty\u0101h\u0101ra iti prokto bhavap\u0101\u015Banik\u1E5Bntana\u1E25||<br> Dh\u012Bgu\u1E47\u0101nsamatikramya nirdhyeya\u1E41 parama\u1E41 vibhum|<br> Dhy\u0101tv\u0101 dhyeya\u1E41 svasa\u1E41vedya\u1E41 dhy\u0101na\u1E41 tacca vidurbudh\u0101\u1E25||<br> Dh\u0101ra\u1E47\u0101 param\u0101tmatva\u1E41 dh\u0101ryate yena sarvad\u0101|<br> Dh\u0101ra\u1E47\u0101 s\u0101 vinirdi\u1E63\u1E6D\u0101 bhavap\u0101\u015Baniv\u0101ri\u1E47\u012B||<br> Svaparasthe\u1E63u bh\u016Bte\u1E63u jagatyasminsam\u0101nadh\u012B\u1E25|<br> \u015Aivo&#39;hamadvit\u012Byo&#39;ha\u1E41 sam\u0101dhi\u1E25 sa para\u1E25 sm\u1E5Bta\u1E25||</p></blockquote><p>iti \u015Br\u012Bmanm\u1E5Btyujidbha\u1E6D\u1E6D\u0101rakanir\u016Bpitan\u012Bty\u0101 dh\u0101ra\u1E47\u0101dibhirapi paratattvasam\u0101ve\u015Ba eva bhavati na tu mitasiddhi\u1E25||6||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 <em>(siddhi\u1E25 s\u0101)</em> \u2014\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F <em>(r\u016Bp\u0101)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 <em>(tad-tad)</em> \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u043C\u0438 [\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(tattva)</em>\u2014 \u043A\u043E\u0442\u043E\u0440\u0430\u044F <em>(y\u0101)</em> [\u0441\u043E\u0437\u0434\u0430\u043D\u0430] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F \u0442\u0435\u043B\u0430, \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, Pr\u0101\u1E47\u0101y\u0101ma, Praty\u0101h\u0101ra, Dh\u0101ra\u1E47\u0101, Dhy\u0101na \u0438 Sam\u0101dhi <em>(deha\u015Buddhi-bh\u016Bta\u015Buddhi-pr\u0101\u1E47\u0101y\u0101ma-praty\u0101h\u0101ra-dh\u0101ra\u1E47\u0101-dhy\u0101na-sam\u0101dhibhi\u1E25)</em>, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0438\u0437-\u0437\u0430 \u0432\u0443\u0430\u043B\u0438 <em>(\u0101vara\u1E47\u0101t)</em> [\u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0430\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u0435\u0442] Moha --\u0442.\u0435. M\u0101y\u0101-- <em>(moha)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0437\u043D\u0430\u043D\u0438\u044E <em>(j\xF1\u0101n\u0101t)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 --\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0441\u0442\u043E \u0442\u0430\u0442\u0442\u0432\u043E\u0439, \u0438\u043B\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C \u042F-- <em>(tattva)</em>. [\u0410\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s, \u0442.\u0435. \u015Aiva,] \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>\u0421\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 <em>(siddhi\u1E25)</em> [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u0438\u0437-\u0437\u0430 \u0432\u0443\u0430\u043B\u0438 <em>(\u0101vara\u1E47\u0101t)</em>, [\u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0430\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u0435\u0442] M\u0101y\u0101, \u0438\u043B\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435 <em>(moha)</em>||6||</strong></p></blockquote><p>Moha <em>(moha\u1E25)</em> \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u0432\u0432\u043E\u0434\u0438\u0442 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mohayati iti)</em>, \u0442.\u0435. M\u0101y\u0101 --\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435-- <em>(m\u0101y\u0101)</em>. \u0418\u0437-\u0437\u0430 \u0432\u0443\u0430\u043B\u0438 <em>(\u0101vara\u1E47\u0101t)</em>, \u043D\u0430\u0431\u0440\u043E\u0448\u0435\u043D\u043D\u043E\u0439 <em>(k\u1E5Bt\u0101t)</em> \u044D\u0442\u043E\u0439 [Moha] <em>(tad)</em>, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 <em>(siddhi\u1E25)</em>, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u0430\u044F <em>(sam\u0101s\u0101dit\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439 <em>(prokta)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(krama)</em> dh\u0101ra\u1E47\u0101 <em>(dh\u0101ra\u1E47\u0101)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F --\u0442.\u0435. \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430-- \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bp\u0101)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(bhoga)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 <em>(tad-tad)</em> \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u043C\u0438 <em>(tattva)</em>|</p><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, [\u044D\u0442\u0430 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430] \u043D\u0435 <em>(na)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(prak\u0101\u015Ba\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattva)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Lak\u1E63m\u012Bkaul\u0101r\u1E47ava <em>(\u015Br\u012Bmat-lak\u1E63m\u012Bkaul\u0101r\u1E47ave)</em>:</p><blockquote><p>\u0411\u043E\u0433 <em>(deva\u1E25)</em>, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C <em>(bhagav\u0101n)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u043E\u0441\u0443\u0449\u0438\u043C <em>(svayambh\u016B\u1E25)</em> [\u0438] \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C <em>(varjita\u1E25)</em> \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0445 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0439 <em>(sa\u1E41sk\u0101ra)</em> [\u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0445] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0439 <em>(janma)</em> --\u0442.\u0435. \u0411\u043E\u0433, \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u044B\u0439 \u0437\u0430\u043A\u043E\u043D\u0443 \u041A\u0430\u0440\u043C\u044B (\u043F\u0440\u0438\u0447\u0438\u043D \u0438 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0439)--, \u0431\u0443\u0434\u0443\u0447\u0438 \u043E\u0431\u043C\u0430\u043D\u0443\u0442\u044B\u043C [\u0421\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 M\u0101y\u0101\u015Bakti] <em>(mohita\u1E25)</em>, \u043D\u0435 <em>(na ca)</em> \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byati)</em> \u0428\u0438\u0432\u0443 <em>(\u015Bivam)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0431\u0435\u0437\u043E \u0432\u0441\u044F\u043A\u0438\u0445 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(nirvikalpam)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432\u044B\u0441\u0448\u0435\u0439 <em>(param)</em> \u041E\u0431\u0438\u0442\u0435\u043B\u044C\u044E <em>(dh\u0101ma)</em>, \u0431\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u043C <em>(an-\u0101di-nidhanam)</em> [\u0438] \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u043F\u0435\u0440\u0435\u0434 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 <em>(pratyak\u1E63am)</em> \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(sarva-jant\u016Bn\u0101m... iti)</em><sup>1</sup>&quot;|</p></blockquote><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0442\u043E\u0433\u043E, \u0447\u044C\u0435 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mohasya)</em> \u0431\u044B\u043B\u043E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043E <em>(vigalita)</em>:</p><blockquote><p>&quot;\u041F\u0440\u0438\u0431\u0435\u0433\u0430\u044F \u043A <em>(\u0101\u015Britya)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47am)</em>, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0439\u0441\u044F \u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhyamam)</em> --\u0442.\u0435. ud\u0101na--, \u043C\u0435\u0436\u0434\u0443 <em>(antaram)</em> \u043F\u043E\u0442\u043E\u043A\u0430\u043C\u0438 <em>(patha)</em> \u043F\u0440\u0430\u043D\u044B (pr\u0101\u1E47a) \u0438 \u0430\u043F\u0430\u043D\u044B (ap\u0101na) <em>(\u0101di)</em>, \u0438 <em>(ca)</em> [\u0432\u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438] \u043E\u0431\u0440\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C <em>(\u0101lambya)</em> \u043A \u0421\u0438\u043B\u0435 \u0417\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-\u015Baktim)</em>, \u0438 <em>(ca eva)</em> \u0443\u0442\u0432\u0435\u0440\u0434\u0438\u0432\u0448\u0438\u0441\u044C <em>(stham)</em> \u0432 \u044D\u0442\u043E\u0439 [\u0421\u0438\u043B\u0435 \u0417\u043D\u0430\u043D\u0438\u044F] <em>(tad)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0437\u0430\u043D\u044F\u0442\u044C <em>(labhet)</em> \u0441\u0432\u043E\u0435 \u043C\u0435\u0441\u0442\u043E <em>(\u0101sanam)</em> [\u0442\u0430\u043C]<sup>2</sup>.</p></blockquote><blockquote><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u0412\u044B\u0441\u0448\u0430\u044F <em>(paramam)</em> \u0421\u043F\u0430\u043D\u0434\u0430, \u0438\u043B\u0438 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F --\u0442.\u0435. \u015Aakti-- <em>(spandanam)</em>, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0430\u044F\u0441\u044F \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 <em>(at\u012Btam tu)</em> \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma] <em>(s\u016Bk\u1E63ma)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u0430 <em>(labhyate)</em> \u043F\u043E\u0441\u043B\u0435 \u043E\u0442\u043A\u0430\u0437\u0430 <em>(tyaktv\u0101)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0433\u043E <em>(sth\u016Bla)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101vam tu)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em> --\u0442.\u0435. \u0433\u0440\u0443\u0431\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u0432\u044B\u0434\u043E\u0445\u0430, \u0432\u0434\u043E\u0445\u0430 \u0438 \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0438 \u0434\u044B\u0445\u0430\u043D\u0438\u044F-- \u0438 \u0437\u0430\u0442\u0435\u043C <em>(atha)</em> \u043E\u0442 \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma] <em>(s\u016Bk\u1E63mam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 --\u0442.\u0435. \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u043D\u043E\u0439 ud\u0101na, \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0439\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 Su\u1E63umn\u0101-- <em>(\u0101ntaram)</em>, [\u0442\u043E \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u044D\u0442\u0430 <em>(tad)</em> Pr\u0101\u1E47\u0101y\u0101ma --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u043F\u0430\u043D\u0434\u0430, \u0438\u043B\u0438 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F-- <em>(pr\u0101\u1E47\u0101y\u0101ma\u1E25)</em>, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 <em>(yasm\u0101t)</em> [Yog\u012B] \u043D\u0435 <em>(na)</em> \u043F\u0430\u0434\u0435\u0442 <em>(cyavate)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em>, \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u0430\u043D\u0430 [\u043A\u0430\u043A \u0441\u0430\u043C\u0430\u044F \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u0430\u044F] <em>(nirdi\u1E63\u1E6Da\u1E25)</em><sup>3</sup>.</p></blockquote><blockquote><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(hi)</em> \u044D\u0442\u043E <em>(y\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(v\u1E5Btti\u1E25)</em> \u0437\u0432\u0443\u043A\u0430 \u043A\u0430\u043A \u0442\u0430\u043A\u043E\u0432\u043E\u0433\u043E <em>(\u015Babda)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em> --\u0442.\u0435. \u043F\u044F\u0442\u0438 Tanm\u0101tra-, \u0438\u043B\u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0442\u0430\u0442\u0442\u0432 \u0441 27 \u043F\u043E 31-- [\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0435] \u0438\u0437 \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439 Prak\u1E5Bti --\u0442\u0430\u0442\u0442\u0432\u0430 13-- <em>(gu\u1E47a)</em> \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(anubh\u016Byate)</em> \u0443\u043C\u043E\u043C <em>(cetas\u0101)</em>, \u0442\u043E \u0447\u0435\u0440\u0435\u0437 \u043E\u0442\u043A\u0430\u0437 <em>(tyaktv\u0101)</em> \u043E\u0442 \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(t\u0101m)</em>, [Yog\u012B] \u0432\u0445\u043E\u0434\u0438\u0442 <em>(pravi\u015Bet)</em> \u0432 \u044D\u0442\u0443 <em>(tad)</em> \u0412\u044B\u0441\u0448\u0443\u044E <em>(paramam)</em> \u041E\u0431\u0438\u0442\u0435\u043B\u044C, \u0438\u043B\u0438 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(dh\u0101ma)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u043C\u044B\u0441\u043B\u0435\u0439 <em>(sva-cetas\u0101)</em><sup>4</sup>. \u042D\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F Praty\u0101h\u0101ra --\u043E\u0442\u0437\u044B\u0432\u0430\u043D\u0438\u0435-- <em>(praty\u0101h\u0101ra\u1E25 iti prokta\u1E25)</em>, \u0442\u043E \u0447\u0442\u043E \u043E\u0442\u0440\u0443\u0431\u0430\u0435\u0442 <em>(nik\u1E5Bntana\u1E25)</em> \u043F\u0435\u0442\u043B\u044E <em>(p\u0101\u015Ba)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F --Sa\u1E41s\u0101ra-- <em>(bhava)</em>.</p></blockquote><blockquote><p>\u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F <em>(samatikramya)</em> \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u044B\u0435 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438 <em>(gu\u1E47\u0101n)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(dh\u012B)</em> [\u0438] \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u044F <em>(dhy\u0101tv\u0101)</em> \u043D\u0430 \u0432\u044B\u0441\u0448\u0443\u044E <em>(paramam)</em> \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0443\u044E [\u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C] <em>(vibhum)</em> \u2014\u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C --\u0442.\u0435. \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438-- <em>(nirdhyeyam)</em>\u2014 \u043A\u0430\u043A \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0421\u0432\u0435\u0442 <em>(sva-sa\u1E41vedyam)</em> \u2014\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 \u0434\u043B\u044F \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhyeyam)</em>\u2014<sup>5</sup>, \u044D\u0442\u043E --\u0442.\u0435. \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0442\u043E \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u043B\u043E\u0441\u044C-- <em>(tad ca)</em> \u043C\u0443\u0434\u0440\u0435\u0446\u044B <em>(budh\u0101\u1E25)</em> \u0437\u043D\u0430\u044E\u0442 <em>(vidu\u1E25)</em> \u043A\u0430\u043A Dhy\u0101na, \u0438\u043B\u0438 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044E <em>(dhy\u0101nam)</em>.</p></blockquote><blockquote><p>Dh\u0101ra\u1E47\u0101, \u0438\u043B\u0438 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em> [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E, \u043A\u043E\u0433\u0434\u0430] \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(parama-\u0101tmatvam)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0438\u043C [\u0432 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438] <em>(dh\u0101ryate... sad\u0101)</em> --\u0442.\u0435. Yog\u012B-- <em>(yena)</em>. \u042D\u0442\u0430 <em>(s\u0101)</em> \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em> \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(vinirdi\u1E63\u1E6D\u0101)</em> \u043A\u0430\u043A \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u0430\u044F \u0443\u0434\u0430\u043B\u0438\u0442\u044C <em>(niv\u0101ri\u1E47\u012B)</em> \u043F\u0435\u0442\u043B\u044E <em>(p\u0101\u015Ba)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(bhava)</em>.</p></blockquote><blockquote><p>\u0412 \u044D\u0442\u043E\u043C <em>(asmin)</em> \u043C\u0438\u0440\u0435 <em>(jagati)</em>, \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 <em>(dh\u012B\u1E25)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(sam\u0101na)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] &#39;\u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u015Aiva <em>(\u015Biva\u1E25)</em>&#39;, &#39;\u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u041E\u0434\u0438\u043D \u0431\u0435\u0437 \u0432\u0442\u043E\u0440\u043E\u0433\u043E <em>(advit\u012Bya\u1E25)</em>&#39;, \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 [\u0432\u0441\u0435\u0445] \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(bh\u016Bte\u1E63u)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0445\u0441\u044F <em>(sthe\u1E63u)</em> \u043A\u0430\u043A \u0441\u0430\u043C <em>(sva)</em> [\u0438] \u0434\u0440\u0443\u0433\u0438\u0435 <em>(para)</em>, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>(sm\u1E5Bta\u1E25)</em> \u0432\u044B\u0441\u0448\u0435\u0435 <em>(sa\u1E25 para\u1E25)</em> Sam\u0101dhi, \u0438\u043B\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u0430\u044F \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(sam\u0101dhi\u1E25... iti)</em>&quot;||</p></blockquote><p>[\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u0430\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C [\u0432\u044B\u0448\u0435]<em>(nir\u016Bpita)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012Bmat... bha\u1E6D\u1E6D\u0101raka)</em> M\u1E5Btyujit --\u0442.\u0435. Netratantra-- <em>(m\u1E5Btyujit)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Dh\u0101ra\u1E47\u0101, \u0438 \u0442.\u043F. <em>(dh\u0101ra\u1E47\u0101-\u0101dibhi\u1E25)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(eva)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 <em>(sam\u0101ve\u015Ba\u1E25)</em> \u0432 \u0412\u044B\u0441\u0448\u0435\u043C <em>(para)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 <em>(tattva)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> [\u0442\u043E\u043B\u044C\u043A\u043E] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 <em>(siddhi\u1E25)</em>||6||</p><ol><li><p>\u0415\u0441\u043B\u0438 \u0432\u044B \u0434\u0443\u043C\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E \u043A\u0430\u043A\u043E\u043C-\u0442\u043E \u0434\u0440\u0443\u0433\u043E\u043C \u0411\u043E\u0433\u0435, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u043C \u043F\u043E\u043C\u0438\u043C\u043E \u0412\u0430\u0441, \u0442\u043E \u044D\u0442\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E \u0432\u0430\u0448\u0435\u043C \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u043C \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0438. \u042D\u0442\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u0412\u0430\u0441 (\u0432\u0430\u0448\u0435\u043C \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u043C \u042F, \u043D\u0435 \u043E \u0432\u0430\u0448\u0435\u043C \u044D\u0433\u043E, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u043C \u0414\u0436\u043E\u043D, \u0425\u0443\u0430\u043D \u0438 \u0442.\u0434.), \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u043E\u0441\u0443\u0449\u0438\u043C \u0438 \u043D\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0437\u0430\u043A\u043E\u043D\u043E\u043C \u041A\u0430\u0440\u043C\u044B. \u042D\u0442\u043E \u0435\u0441\u0442\u044C \u0422\u044B, \u043E\u0431\u043C\u0430\u043D\u0443\u0442\u044B\u0439 \u0442\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0438\u043B\u043E\u0439 \u043C\u0430\u0439\u0438 (\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C), \u043D\u0435 \u043C\u043E\u0436\u0435\u0448\u044C \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0428\u0438\u0432\u0443 (\u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443), \u043A\u0442\u043E \u043B\u0438\u0448\u0435\u043D \u043B\u044E\u0431\u044B\u0445 \u043C\u044B\u0441\u043B\u0435\u0439, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0435\u0439 \u041E\u0431\u0438\u0442\u0435\u043B\u044C\u044E, \u0438\u043B\u0438 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C, \u043A\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043D\u0438 \u043D\u0430\u0447\u0430\u043B\u0430, \u043D\u0438 \u043A\u043E\u043D\u0446\u0430, \u0438 \u043A\u0442\u043E \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u0435\u0440\u0435\u0434 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u0442.\u0435. \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043E\u0447\u0435\u0432\u0438\u0434\u0435\u043D \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043D\u0438\u0445. \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u043D\u0430\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0443\u0447\u0435\u043D\u044B\u043C \u0422\u0440\u0438\u043A\u0438 \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0431\u044B\u0442\u044C, \u043D\u043E \u0435\u0441\u043B\u0438 \u043D\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0432\u044B - \u043F\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443 \u0411\u043E\u0433, \u0432\u044B \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u043E\u0439\u043C\u0435\u0442\u0435 \u0422\u0440\u0438\u043A\u0443 \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435. \u0414\u0430\u0436\u0435 \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 (\u0442.\u0435. \u0440\u0435\u0447\u044C \u0438\u0434\u0435\u0442 \u043E \u0100\u1E47avop\u0101ya), \u0433\u0434\u0435 \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0442\u043E\u0447\u043A\u0430 \u0437\u0440\u0435\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0438 \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u0439-\u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0440\u0430\u0431\u0441\u0442\u0432\u043E-\u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0442.\u043F. \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0441\u0430\u043C\u043E\u043C \u0440\u0430\u0437\u0433\u0430\u0440\u0435, \u0432\u044B \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u044B \u0443\u043F\u0443\u0441\u043A\u0430\u0442\u044C \u0438\u0437 \u0432\u0438\u0434\u0443 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C.</p></li><li><p>Ud\u0101na \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 Su\u1E63umn\u0101 (\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u0442\u043E\u043D\u043A\u0438\u0439 \u043A\u0430\u043D\u0430\u043B). \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, ap\u0101na \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 I\u1E0D\u0101 \u0438 pr\u0101\u1E47a \u2014 \u0441 Pi\u1E45gal\u0101. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0435 \u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442, \u0447\u0442\u043E Ud\u0101na \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435, \u043C\u0435\u0436\u0434\u0443 \u043F\u043E\u0442\u043E\u043A\u0430\u043C\u0438 pr\u0101\u1E47a \u0438 ap\u0101na, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 Su\u1E63umn\u0101 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u043C\u0435\u0436\u0434\u0443 \u043F\u043E\u0442\u043E\u043A\u0430\u043C\u0438 (n\u0101\u1E0D\u012B-s, \u0438\u043B\u0438 \u0442\u043E\u043D\u043A\u0438\u043C\u0438 \u043A\u0430\u043D\u0430\u043B\u0430\u043C\u0438), \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C\u0438 \u043A\u0430\u043A Pi\u1E45gal\u0101 \u0438 I\u1E0D\u0101. \u041F\u043E \u043C\u0435\u0440\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A Ud\u0101na \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F, \u0435\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 \u0438 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0438\u0442 \u0432 \u0421\u0438\u043B\u0443 \u0417\u043D\u0430\u043D\u0438\u044F (J\xF1\u0101na\u015Bakti) \u0438\u0437-\u0437\u0430 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F Cit, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u015Aiva). \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432, Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0437\u0430\u043D\u044F\u0442\u044C \u0441\u0432\u043E\u0435 \u043C\u0435\u0441\u0442\u043E \u0442\u0430\u043C, \u0432 J\xF1\u0101na\u015Bakti.</p></li><li><p>\u0413\u0440\u0443\u0431\u0430\u044F pr\u0101\u1E47\u0101y\u0101ma \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0432\u044B\u0434\u043E\u0445, \u0432\u0434\u043E\u0445 \u0438 \u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0430 \u0434\u044B\u0445\u0430\u043D\u0438\u044F. \u0422\u043E\u043D\u043A\u0430\u044F pr\u0101\u1E47\u0101y\u0101ma \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0423\u0434\u0430\u043D\u044B (ud\u0101na) \u0432 \u0421\u0443\u0448\u0443\u043C\u043D\u0435 (Su\u1E63umn\u0101). \u041A\u043E\u0433\u0434\u0430 \u0423\u0434\u0430\u043D\u0430 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u0421\u0438\u043B\u0443 \u0417\u043D\u0430\u043D\u0438\u0439 \u0438, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432, Yog\u012B \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0432 \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u043F\u0430\u043D\u0434\u0435 (Spanda), \u0438\u043B\u0438 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u0438, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u043E\u0439 \u041F\u0440\u0430\u043D\u0430\u044F\u043C\u044B (pr\u0101\u1E47\u0101y\u0101ma). \u042D\u0442\u0430 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u0430\u044F pr\u0101\u1E47\u0101y\u0101ma, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0434\u0430\u0436\u0435 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u0442\u043E\u043D\u043A\u043E\u0439, \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u0430 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 \u0438\u043B\u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C (\u0101y\u0101ma) \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 (pr\u0101\u1E47a), \u043D\u043E \u0441\u043A\u043E\u0440\u0435\u0435 \u043A\u0430\u043A \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439, \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0432 \u0433\u0440\u0443\u0431\u043E\u0439 \u0438 \u0442\u043E\u043D\u043A\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma-s, \u0442.\u0435. pr\u0101\u1E47a (\u0432\u044B\u0434\u043E\u0445), ap\u0101na (\u0432\u0434\u043E\u0445), sam\u0101na (\u0437\u0430\u0434\u0435\u0440\u0436\u043A\u0430) \u0438 ud\u0101na. \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u043F\u0430\u043D\u0434\u0430, \u0438\u043B\u0438 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F \u0435\u0441\u0442\u044C \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u015Aakti (\u0421\u0438\u043B\u0430 \u0411\u043E\u0433\u0430), \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0432\u0441\u0435\u0445 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043D\u0435 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u0447\u0442\u043E \u043B\u0443\u0447\u0448\u0430\u044F pr\u0101\u1E47\u0101y\u0101ma \u2014\u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u0441\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0438\u043B\u0438 pr\u0101\u1E47a-s, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0442 \u0432\u043D\u043E\u0432\u044C \u043A \u0441\u0432\u043E\u0435\u043C\u0443 \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044E \u0432 \u041D\u0435\u043C.</p></li></ol><p>\u0414\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E Yog\u012B \u043D\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u043F\u0430\u0434\u0435\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433 \u015Aakti, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u0430 \u043E\u0442 \u0421\u0432\u043E\u0435\u0433\u043E \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044F \u015Aiva. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0432\u0448\u0438\u0439 \u0441\u0432\u043E\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u0427\u0438\u0442 (Cit), \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C (\u0442.\u0435. \u0441 \u015Aiva), \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u043A \u043E\u0431\u044B\u0447\u043D\u043E\u043C\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u043A \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F\u043C. OK, \u043F\u043E\u043A\u0430 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E.</p><ol start="4"><li><p>\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;sva-cetas\u0101&quot; \u043D\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 &quot;\u0441/\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0443\u043C\u0430&quot;, \u043D\u043E &quot;\u0905\u0935\u093F\u0915\u0932\u094D\u092A\u0938\u0902\u0935\u093F\u0924\u094D\u092A\u0930\u092E\u093E\u0930\u094D\u0936\u0928\u0947\u0928 &quot; - &quot;avikalpasa\u1E41vitparam\u0101r\u015Banena&quot; \u0438\u043B\u0438 &quot;\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u044F (param\u0101r\u015Banena) \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F (sa\u1E41vid), \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u043C\u044B\u0441\u043B\u0435\u0439 (avikalpa)&quot;. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u043E\u0439\u0442\u0438 \u0432 \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432 \u043F\u043E\u043B\u043D\u043E\u0439 \u041E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li><li><p>\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 &quot;svasa\u1E41vedyam&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0938\u094D\u0935\u092A\u094D\u0930\u0915\u093E\u0936\u092E\u094D &quot; - &quot;svaprak\u0101\u015Bam&quot; (\u043A\u0430\u043A \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u0432\u0435\u0442), \u0438 &quot;dhyeyam&quot;\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0927\u094D\u092F\u093E\u0928\u093E\u0930\u094D\u0939\u092E\u094D &quot; - &quot;dhy\u0101n\u0101rham&quot;, \u0438\u043B\u0438 &quot;\u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u0439 \u0434\u043B\u044F \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438&quot;. \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0432\u043E \u0444\u0440\u0430\u0437\u0435 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0438\u0435, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E, \u043A\u0430\u043A \u043C\u043E\u0436\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0432\u044B\u0441\u0448\u0443\u044E \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0443\u044E \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C? \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u043F\u043E\u0437\u0436\u0435 \u0431\u044B\u043B\u043E \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;dhyeya\u1E41 svasa\u1E41vedyam&quot;. \u041A\u043E\u0440\u043E\u0447\u0435, \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0412\u044B\u0441\u0448\u0443\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438, \u0430 \u0412\u044B\u0441\u0448\u0438\u043C \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A\u043E \u0432\u0441\u0435\u043C\u0443. \u041D\u043E \u043C\u043E\u0436\u043D\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u041D\u0435\u0433\u043E, \u0442\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u043D\u0430 \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0421\u0432\u0435\u0442, \u0442.\u0435. \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u044F, \u0447\u0442\u043E \u0432\u044B \u0435\u0441\u0442\u044C \u041E\u043D. \u0422\u0435\u0440\u043C\u0438\u043D &quot;dhy\u0101tv\u0101&quot; (\u043C\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u044F) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C \u0437\u0434\u0435\u0441\u044C \u043A\u0430\u043A &quot;\u0935\u093F\u092E\u0943\u0936\u094D\u092F &quot; - &quot;vim\u1E5B\u015Bya&quot; (\u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u044F, \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044F, \u0437\u043D\u0430\u044F). \u0412 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043A\u0430\u043A \u043D\u0430 \u043E\u0431\u044A\u0435\u043A\u0442, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u041D\u0438\u043C. \u0422\u0435\u043F\u0435\u0440\u044C \u0441\u043C\u044B\u0441\u043B \u043F\u043E\u043D\u044F\u0442\u0435\u043D.</p></li></ol></div>',1),p=[i];function o(h,d,s,u,n,v){return e(),m("div",null,p)}var l=a(r,[["render",o]]);export{b as __pageData,l as default};
